static const char *TAG = "web";

// Embedded web files (gzipped, generated by scripts/gen_web_assets.py at build time)
#include "web_assets.h"

static esp_err_t send_gzipped(httpd_req_t *req, const char *content_type,
                               const char *data, size_t len)
{
    httpd_resp_set_type(req, content_type);
    httpd_resp_set_hdr(req, "Content-Encoding", "gzip");
    return httpd_resp_send(req, data, len);
}

// Shared NFC state — defined in main.c
extern pn532_t nfc_dev;
extern bool nfc_busy;

typedef enum {
    CARD_UNKNOWN = 0,
    CARD_MIFARE_CLASSIC,
    CARD_MIFARE_ULTRALIGHT
} card_type_t;

#define MAX_TAG_DATA 256
#define CLASSIC_BLOCKS_TO_READ 16
#define UL_PAGES_TO_READ 44
#define QIDI_BLOCK 4

typedef struct {
    bool valid;
    uint8_t uid[7];
    uint8_t uid_len;
    card_type_t card_type;
    uint8_t data[MAX_TAG_DATA];
    uint16_t data_len;
    uint8_t pages_read;
    uint8_t blocks_read;
    bool is_qidi_format;
    bool auth_failed;
    bool read_failed;
    uint32_t timestamp;
} tag_data_t;

static inline uint32_t millis(void)
{
    return (uint32_t)(esp_timer_get_time() / 1000);
}

// Shared tag state
tag_data_t last_tag = {};
uint8_t prev_uid[7] = {0};
uint8_t prev_uid_len = 0;
bool tag_present = false;

// LED timing
uint32_t led_ok_until = 0;
uint32_t led_err_until = 0;

static uint8_t default_key[6] = {0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF};

static const char *card_type_name(card_type_t ct)
{
    switch (ct) {
        case CARD_MIFARE_CLASSIC:    return "MIFARE Classic";
        case CARD_MIFARE_ULTRALIGHT: return "MIFARE Ultralight / NTAG";
        default:                     return "Unknown";
    }
}

static card_type_t detect_card_type(uint8_t uid_len)
{
    switch (uid_len) {
        case 4:  return CARD_MIFARE_CLASSIC;
        case 7:  return CARD_MIFARE_ULTRALIGHT;
        default: return CARD_UNKNOWN;
    }
}

// --- Helper to extract URL query param ---
static bool get_query_param(httpd_req_t *req, const char *key, char *val, size_t val_size)
{
    size_t buf_len = httpd_req_get_url_query_len(req) + 1;
    if (buf_len <= 1) return false;

    char *buf = malloc(buf_len);
    if (!buf) return false;

    if (httpd_req_get_url_query_str(req, buf, buf_len) != ESP_OK) {
        free(buf);
        return false;
    }

    esp_err_t err = httpd_query_key_value(buf, key, val, val_size);
    free(buf);
    return err == ESP_OK;
}

// URL-decode in place
static void url_decode(char *s)
{
    char *r = s, *w = s;
    while (*r) {
        if (*r == '+') {
            *w++ = ' ';
            r++;
        } else if (*r == '%' && r[1] && r[2]) {
            char hex[3] = {r[1], r[2], 0};
            *w++ = (char)strtol(hex, NULL, 16);
            r += 3;
        } else {
            *w++ = *r++;
        }
    }
    *w = '\0';
}

// --- Helper to extract POST form field ---
static bool get_post_param(const char *body, const char *key, char *val, size_t val_size)
{
    if (httpd_query_key_value(body, key, val, val_size) != ESP_OK) return false;
    url_decode(val);
    return true;
}

